#!/usr/bin/env bash
# agentic.sh — Agentic Protocol CLI for 小红书 AI 自媒体博主.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 9.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
# shellcheck source=../lib/common.sh
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="小红书 AI 自媒体博主"
DIM_COUNT=6

usage() {
  cat <<EOF
agentic.sh — Agentic Protocol CLI for ${INDUSTRY}

拿到 ${INDUSTRY} 行业的新问题时，按 ${DIM_COUNT} 个研究维度做功课再答。
不直接给答案，而是引导你用资深从业者的研究维度收集信息。

USAGE:
  ./agentic.sh                # interactive walkthrough
  ./agentic.sh --dry-run      # walk through but skip file write
  ./agentic.sh --json         # emit JSON to stdout
  ./agentic.sh --explain      # show backing mental models + sources
  ./agentic.sh --help         # this message
EOF
}

explain() {
  cat <<'EOT'
这个 Agentic Protocol 把这一行人面对新问题的研究维度结构化。

研究维度 (6 个):
  9.1 选题判定
  9.2 标题与封面
  9.3 正文与内容结构
  9.4 AI 工具与制作
  9.5 合规与质检
  9.6 发布与复盘

来源: synthesis.md Section 9 + Section 1.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a DIM_TITLES=(
  "选题判定"
  "标题与封面"
  "正文与内容结构"
  "AI 工具与制作"
  "合规与质检"
  "发布与复盘"
)
declare -a DIM_QUESTIONS=(
  "目标人群(小红书泛知识/年轻女性)、AI 赛道切入点、是否有搜索量/蓝海。"
  "标题公式与关键词前置、封面三秒可读性、3:4 大字报、CTR 预期。"
  "钩子、6 段式、利他价值、CTA、收藏诱因。"
  "内容类型(图文/口播/数字人/资讯)对应工具链、AI 辅助 vs 全自动。"
  "是否用了 AI(含润色)→AIGC 标识、违禁词、公约 2.0 红线(无对立/焦虑/虚假人设)。"
  "发布时机、薯条、收藏率/互动率/小眼睛、迭代点。"
)
declare -a DIM_SOURCES=(
  "新红/千瓜/蝉小红 热搜与蓝海词 + 3-5 个对标号 + 搜索下拉。"
  "Track 04 爆款四件套 + 对标爆款封面。"
  "Track 03 正文 SOP + Track 01 博主方法论。"
  "Track 02 工具决策树。"
  "小红书官方规则(Track 04/05) + 违禁词工具。"
  "创作服务平台数据后台(唯一一手)。"
)
declare -a DIM_OUTPUT_FORMATS=(
  "选定选题 + 对标依据 + 核心 SEO 关键词。"
  "标题 3 选 1 + 封面方案(模板/大字/对比色)。"
  "正文结构 + 钩子 + CTA，标\"哪里需真实素材\"。"
  "工具组合 + AI 出稿/人工重写分工(70/30)。"
  "三道闸自检清单结果(标识/违禁/原创度)。"
  "发布计划 + 复盘指标阈值(互动率<3% 改标题) + 迭代方向。"
)
declare -a DIM_FINDINGS=()

if [[ $JSON -eq 0 ]]; then
  ms_section "${INDUSTRY} · Agentic Protocol"
  ms_info "拿到的问题是什么? (输入完后，敲一个空行结束)"
  echo
fi

PROBLEM="$(ms_read_multiline)"
ms_buffer_append "# ${INDUSTRY} — Agentic Protocol Report"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 问题"
ms_buffer_append ""
ms_buffer_append "$PROBLEM"
ms_buffer_append ""

for i in "${!DIM_TITLES[@]}"; do
  if [[ $JSON -eq 0 ]]; then
    ms_section "${DIM_TITLES[$i]}"
    echo "看什么:    ${DIM_QUESTIONS[$i]}"
    echo "在哪看:    ${DIM_SOURCES[$i]}"
    echo "输出格式:  ${DIM_OUTPUT_FORMATS[$i]}"
    echo
    ms_prompt "你的发现 / 推断 (空行结束):"
    echo
  fi
  finding="$(ms_read_multiline)"
  DIM_FINDINGS+=("$finding")

  ms_buffer_append "## ${DIM_TITLES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**看什么**: ${DIM_QUESTIONS[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**在哪看**: ${DIM_SOURCES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**发现**:"
  ms_buffer_append ""
  ms_buffer_append "$finding"
  ms_buffer_append ""
done

if [[ $JSON -eq 1 ]]; then
  args=("problem" "$PROBLEM")
  for i in "${!DIM_TITLES[@]}"; do
    args+=("dim_${i}_title" "${DIM_TITLES[$i]}")
    args+=("dim_${i}_finding" "${DIM_FINDINGS[$i]}")
  done
  ms_emit_json "${args[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "agentic-protocol"
fi
